const estado = $input.all()[0]?.json || {};
const historico = $input.all()[1]?.json?.operacoes || [];

const hoje = new Date().toLocaleDateString('pt-BR');
const ops_hoje = historico.filter(op => {
  const data = new Date(op.timestamp || op.data);
  return data.toLocaleDateString('pt-BR') === hoje;
});

const ganhos = ops_hoje.filter(op => (op.resultado || 0) > 0);
const perdas = ops_hoje.filter(op => (op.resultado || 0) < 0);
const pnl_dia = ops_hoje.reduce((s, op) => s + (op.resultado || 0), 0);

const saldo = estado.saldo || 0;
const pnl_total = estado.pnl_total || 0;

const emoji_dia = pnl_dia >= 0 ? '🟢' : '🔴';
const sinal_dia = pnl_dia >= 0 ? '+' : '';

return [{ json: {
  mensagem: `📊 *RELATÓRIO DIÁRIO — ${hoje}*\n\n` +
    `${emoji_dia} *P&L do dia:* ${sinal_dia}R$ ${pnl_dia.toFixed(2)}\n` +
    `📈 *Operações:* ${ops_hoje.length} (✅ ${ganhos.length} / ❌ ${perdas.length})\n` +
    `💰 *Saldo atual:* R$ ${saldo.toFixed(2)}\n` +
    `📉 *P&L acumulado:* R$ ${pnl_total.toFixed(2)}\n\n` +
    `_Trader-good • ${new Date().toLocaleTimeString('pt-BR')}_`
}}];
